class ActivationModule(nn.Module):
    def __init__(self, activation='relu'):
        super().__init__()
        activations = {
            'sigmoid': nn.Sigmoid(),
            'tanh': nn.Tanh(),
            'relu': nn.ReLU(),
            'leaky_relu': nn.LeakyReLU(0.01),
            'elu': nn.ELU(),
            'gelu': nn.GELU(),
            'silu': nn.SiLU(),  # Swish
            'softmax': nn.Softmax(dim=1)
        }
        self.activation = activations.get(activation, nn.ReLU())

    def forward(self, x):
        return self.activation(x)

