class GradientDescentOptimizers:
    """Various gradient descent optimizers"""

    def __init__(self, learning_rate=0.01):
        self.lr = learning_rate
        self.momentum = 0
        self.velocity = {}
        self.squared_grads = {}

    def sgd(self, params, grads):
        """Stochastic Gradient Descent"""
        for param, grad in zip(params, grads):
            param -= self.lr * grad

    def sgd_momentum(self, params, grads, momentum=0.9):
        """SGD with momentum"""
        for i, (param, grad) in enumerate(zip(params, grads)):
            if i not in self.velocity:
                self.velocity[i] = 0
            self.velocity[i] = momentum * self.velocity[i] + self.lr * grad
            param -= self.velocity[i]

    def adam(self, params, grads, t, beta1=0.9, beta2=0.999, eps=1e-8):
        """Adam optimizer"""
        for i, (param, grad) in enumerate(zip(params, grads)):
            if i not in self.velocity:
                self.velocity[i] = 0
                self.squared_grads[i] = 0

            self.velocity[i] = beta1 * self.velocity[i] + (1 - beta1) * grad
            self.squared_grads[i] = beta2 * self.squared_grads[i] + (1 - beta2) * (grad**2)

            m_hat = self.velocity[i] / (1 - beta1**t)
            v_hat = self.squared_grads[i] / (1 - beta2**t)

            param -= self.lr * m_hat / (np.sqrt(v_hat) + eps)

